$giphyKey = "13oo1pWtRjIYd0FDf6GaWSqwJxr0NrdG"; $categories = @(@{folder="trending"; query="trending memes"}, @{folder="dank"; query="dank memes"}, @{folder="funny"; query="funny memes"}, @{folder="indian"; query="indian memes bollywood cricket"}); $limitPerCategory = 250; $totalDownloaded = 0; Write-Host " Downloading 1000 GIPHY GIFs..." -ForegroundColor Green; foreach ($cat in $categories) { Write-Host "`n $($cat.folder.ToUpper())..." -ForegroundColor Yellow; $folderPath = "backend\memes\gifs\$($cat.folder)"; New-Item -ItemType Directory -Force -Path $folderPath | Out-Null; $apiUrl = "https://api.giphy.com/v1/gifs/search?api_key=$giphyKey&q=$($cat.query)&limit=$limitPerCategory&rating=g"; try { $response = Invoke-RestMethod -Uri $apiUrl -TimeoutSec 30; $gifs = $response.data; $categoryCount = 0; foreach ($gif in $gifs) { if ($gif.images.fixed_width.url) { $gifUrl = $gif.images.fixed_width.url; $filename = "$folderPath\$([guid]::NewGuid()).gif"; try { Invoke-WebRequest -Uri $gifUrl -OutFile $filename -UseBasicParsing -TimeoutSec 10; $categoryCount++; $totalDownloaded++; if ($categoryCount % 50 -eq 0) { Write-Host "    $categoryCount/$limitPerCategory" -ForegroundColor Cyan } } catch {} } }; Write-Host " $($cat.folder): $categoryCount GIFs" -ForegroundColor Green } catch { Write-Host " $($cat.folder): $_" -ForegroundColor Red } }; Write-Host "`n TOTAL: $totalDownloaded GIFs in backend/memes/gifs/" -ForegroundColor Green
